import{c as s}from"./app.8935f5f1.js";const n={},a=s('<h3 id="安装" tabindex="-1"><a class="header-anchor" href="#安装" aria-hidden="true">#</a> 安装</h3><div class="language-bash ext-sh"><pre class="language-bash"><code>\n\n<span class="token comment">#当前所在目录/app/omodel/redis</span>\n\n<span class="token comment">#解压 tar.gz   -C 指定目录</span>\n<span class="token function">tar</span> -zvxf redis-5.0.7.tar.gz\n\n<span class="token comment">#一般都会将redis目录放置到 /usr/local/redis目录，所以这里输入下面命令将目前在/root目录下的redis-5.0.7文件夹更改目录，同时更改文件夹名称为redis</span>\n<span class="token function">mv</span>  redis-5.0.7  redis\n\n<span class="token comment"># make  make &amp;&amp; make install PREFIX=/usr/local/redis （指定安装目录）</span>\n\n <span class="token function">make</span> <span class="token operator">&amp;&amp;</span> <span class="token function">make</span> <span class="token function">install</span> <span class="token assign-left variable">PREFIX</span><span class="token operator">=</span>/usr/local/redis\n<span class="token comment">#启动： 进入 bin/ ./redis-server</span>\n\n./bin/redis-server<span class="token operator">&amp;</span> ./redis.conf\n<span class="token comment">#./bin/redis-server&amp; ./redis.conf 带配置文件启动</span>\n\n</code></pre></div><ul><li>redis 需要配置的</li></ul><div class="language-bash ext-sh"><pre class="language-bash"><code><span class="token comment"># 关闭保护模式</span>\nprotected-mode no\n<span class="token comment"># 以守护进程后台模式运行</span>\ndaemonize <span class="token function">yes</span>\n<span class="token comment"># 绑定本机ip</span>\n<span class="token builtin class-name">bind</span> <span class="token number">172.18</span>.203.30\n<span class="token comment"># redis进程文件</span>\npidfile /usr/local/redis/redis_6379.pid\n<span class="token comment"># 日志文件</span>\nlogfile /usr/local/redis/log/redis_6379.log\n<span class="token comment"># 快照数据存放目录,一定是目录</span>\n<span class="token function">dir</span> /usr/local/redis/data/\n\nprotected-mode no    <span class="token comment"># 关闭保护模式</span>\ndaemonize <span class="token function">yes</span>        <span class="token comment"># 守护进程模式开启(可以后台运行)</span>\n<span class="token comment">#bind 127.0.0.1      #注释掉，监听所有的IP地址(如果需要其他ip的redis客户端访问)</span>\n\nrequirepass redispwd <span class="token comment">#可以修改密码，requirepass 后边添加redis密码</span>\nport <span class="token number">6666</span>            <span class="token comment">#可以修改端口号，默认是6379</span>\n\n<span class="token comment"># 检查端口</span>\n<span class="token function">netstat</span> -ltnp <span class="token operator">|</span><span class="token function">grep</span> <span class="token number">6379</span>\n</code></pre></div><p><code>netstat -ltnp |grep 6379</code></p><h3 id="redis-cli" tabindex="-1"><a class="header-anchor" href="#redis-cli" aria-hidden="true">#</a> redis-cli</h3><div class="language-bash ext-sh"><pre class="language-bash"><code><span class="token comment"># 启动redis客户端（提示：参数- h {ip} -p {port} ）</span>\n./redis-cli -h <span class="token number">192.168</span>.1.11 -p <span class="token number">6379</span>\n</code></pre></div><h3 id="redis字符串-string" tabindex="-1"><a class="header-anchor" href="#redis字符串-string" aria-hidden="true">#</a> redis字符串(String)</h3><ul><li>string是redis最基本的类型，一个key对应一个value。string类型是Redis最基本的数据类型，一个键最大能存储<strong>512MB</strong>。</li></ul><ul><li><strong>应用场景</strong> String通常用于保存单个字符串或JSON字符串数据,常用的场景有：统计网站访问数量、当前在线人数、微博数、粉丝数等， 全局递增ID等 。</li></ul>',10);n.render=function(s,n){return a};export{n as default};
